import { makePatchUserEmailHandler, isValidEmail, User, UserRepository } from './patchUserEmail';

// ---------------------------------------------------------------------------
// Test helpers
// ---------------------------------------------------------------------------

/** Build a minimal mock Express response with chainable status/json */
function makeRes() {
  const res = {
    status: jest.fn(),
    json: jest.fn(),
  };
  // Allow chaining: res.status(200).json({})
  res.status.mockReturnValue(res);
  res.json.mockReturnValue(res);
  return res;
}

/** Build a mock Express request */
function makeReq(id: string, body: Record<string, unknown>) {
  return { params: { id }, body } as any;
}

/** Build a mock UserRepository with sensible defaults */
function makeRepo(overrides: Partial<UserRepository> = {}): UserRepository {
  return {
    findById: jest.fn().mockResolvedValue(null),
    findByEmail: jest.fn().mockResolvedValue(null),
    updateEmail: jest.fn().mockResolvedValue(null),
    ...overrides,
  };
}

const ALICE: User = { id: 'user-1', email: 'alice@example.com', name: 'Alice' };
const BOB: User   = { id: 'user-2', email: 'bob@example.com',   name: 'Bob'   };

// ---------------------------------------------------------------------------
// isValidEmail — unit tests
// ---------------------------------------------------------------------------

describe('isValidEmail', () => {
  it('accepts a standard email', () => {
    expect(isValidEmail('user@example.com')).toBe(true);
  });

  it('accepts an email with subdomains', () => {
    expect(isValidEmail('user@mail.example.co.uk')).toBe(true);
  });

  it('rejects a plain string with no @', () => {
    expect(isValidEmail('not-an-email')).toBe(false);
  });

  it('rejects an email with no domain dot', () => {
    expect(isValidEmail('user@localhost')).toBe(false);
  });

  it('rejects an email with spaces', () => {
    expect(isValidEmail('user @example.com')).toBe(false);
  });

  it('rejects undefined', () => {
    expect(isValidEmail(undefined)).toBe(false);
  });

  it('rejects null', () => {
    expect(isValidEmail(null)).toBe(false);
  });

  it('rejects a number', () => {
    expect(isValidEmail(42)).toBe(false);
  });

  it('rejects an empty string', () => {
    expect(isValidEmail('')).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// AC1 — valid update returns 200 with updated user object
// ---------------------------------------------------------------------------

describe('AC1: successful email update', () => {
  it('returns 200 with the updated user returned by the repository', async () => {
    const updated: User = { ...ALICE, email: 'alice-new@example.com' };
    const repo = makeRepo({
      findById: jest.fn().mockResolvedValue(ALICE),
      findByEmail: jest.fn().mockResolvedValue(null),       // new email not in use
      updateEmail: jest.fn().mockResolvedValue(updated),
    });
    const handler = makePatchUserEmailHandler(repo);
    const req = makeReq('user-1', { email: 'alice-new@example.com' });
    const res = makeRes();

    await handler(req, res);

    expect(res.status).toHaveBeenCalledWith(200);
    expect(res.json).toHaveBeenCalledWith(updated);
  });

  it('calls updateEmail with the correct arguments', async () => {
    const updated: User = { ...ALICE, email: 'alice-new@example.com' };
    const updateEmail = jest.fn().mockResolvedValue(updated);
    const repo = makeRepo({
      findById: jest.fn().mockResolvedValue(ALICE),
      findByEmail: jest.fn().mockResolvedValue(null),
      updateEmail,
    });
    const handler = makePatchUserEmailHandler(repo);
    const req = makeReq('user-1', { email: 'alice-new@example.com' });
    const res = makeRes();

    await handler(req, res);

    expect(updateEmail).toHaveBeenCalledWith('user-1', 'alice-new@example.com');
  });
});

// ---------------------------------------------------------------------------
// AC2 — email already in use by another user → 409
// ---------------------------------------------------------------------------

describe('AC2: email already in use', () => {
  it('returns 409 with EMAIL_ALREADY_IN_USE when the email belongs to another user', async () => {
    const repo = makeRepo({
      findById: jest.fn().mockResolvedValue(ALICE),          // Alice exists
      findByEmail: jest.fn().mockResolvedValue(BOB),         // email belongs to Bob
    });
    const handler = makePatchUserEmailHandler(repo);
    const req = makeReq('user-1', { email: 'bob@example.com' });
    const res = makeRes();

    await handler(req, res);

    expect(res.status).toHaveBeenCalledWith(409);
    expect(res.json).toHaveBeenCalledWith(
      expect.objectContaining({
        error: expect.objectContaining({ code: 'EMAIL_ALREADY_IN_USE' }),
      }),
    );
  });

  it('does NOT call updateEmail when email is already in use', async () => {
    const updateEmail = jest.fn();
    const repo = makeRepo({
      findById: jest.fn().mockResolvedValue(ALICE),
      findByEmail: jest.fn().mockResolvedValue(BOB),
      updateEmail,
    });
    const handler = makePatchUserEmailHandler(repo);
    const req = makeReq('user-1', { email: 'bob@example.com' });
    const res = makeRes();

    await handler(req, res);

    expect(updateEmail).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// AC3 — invalid email format → 400
// ---------------------------------------------------------------------------

describe('AC3: invalid email format', () => {
  const invalidEmails = [
    'not-an-email',
    'missing-at-sign',
    '@no-local.com',
    'no-domain@',
    'spaces in@email.com',
    '',
  ];

  it.each(invalidEmails)(
    'returns 400 with INVALID_EMAIL_FORMAT for "%s"',
    async (badEmail) => {
      const repo = makeRepo();
      const handler = makePatchUserEmailHandler(repo);
      const req = makeReq('user-1', { email: badEmail });
      const res = makeRes();

      await handler(req, res);

      expect(res.status).toHaveBeenCalledWith(400);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({ code: 'INVALID_EMAIL_FORMAT' }),
        }),
      );
    },
  );

  it('returns 400 when email field is missing from the body', async () => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);
    const req = makeReq('user-1', {});          // no email key
    const res = makeRes();

    await handler(req, res);

    expect(res.status).toHaveBeenCalledWith(400);
    expect(res.json).toHaveBeenCalledWith(
      expect.objectContaining({
        error: expect.objectContaining({ code: 'INVALID_EMAIL_FORMAT' }),
      }),
    );
  });

  it('does NOT call findById when email format is invalid', async () => {
    const findById = jest.fn();
    const repo = makeRepo({ findById });
    const handler = makePatchUserEmailHandler(repo);
    const req = makeReq('user-1', { email: 'not-an-email' });
    const res = makeRes();

    await handler(req, res);

    expect(findById).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// AC4 — user not found → 404
// ---------------------------------------------------------------------------

describe('AC4: user not found', () => {
  it('returns 404 with USER_NOT_FOUND when no user matches the id', async () => {
    const repo = makeRepo({
      findById: jest.fn().mockResolvedValue(null),
    });
    const handler = makePatchUserEmailHandler(repo);
    const req = makeReq('nonexistent-id', { email: 'new@example.com' });
    const res = makeRes();

    await handler(req, res);

    expect(res.status).toHaveBeenCalledWith(404);
    expect(res.json).toHaveBeenCalledWith(
      expect.objectContaining({
        error: expect.objectContaining({ code: 'USER_NOT_FOUND' }),
      }),
    );
  });

  it('does NOT call updateEmail when user is not found', async () => {
    const updateEmail = jest.fn();
    const repo = makeRepo({
      findById: jest.fn().mockResolvedValue(null),
      updateEmail,
    });
    const handler = makePatchUserEmailHandler(repo);
    const req = makeReq('ghost-id', { email: 'new@example.com' });
    const res = makeRes();

    await handler(req, res);

    expect(updateEmail).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// AC5 — same email → 200, no change (idempotent)
// ---------------------------------------------------------------------------

describe('AC5: idempotent same-email update', () => {
  it('returns 200 with the existing user object when email is unchanged', async () => {
    const repo = makeRepo({
      findById: jest.fn().mockResolvedValue(ALICE),
    });
    const handler = makePatchUserEmailHandler(repo);
    const req = makeReq('user-1', { email: ALICE.email }); // same email
    const res = makeRes();

    await handler(req, res);

    expect(res.status).toHaveBeenCalledWith(200);
    expect(res.json).toHaveBeenCalledWith(ALICE);
  });

  it('does NOT call updateEmail when email is unchanged', async () => {
    const updateEmail = jest.fn();
    const repo = makeRepo({
      findById: jest.fn().mockResolvedValue(ALICE),
      updateEmail,
    });
    const handler = makePatchUserEmailHandler(repo);
    const req = makeReq('user-1', { email: ALICE.email });
    const res = makeRes();

    await handler(req, res);

    expect(updateEmail).not.toHaveBeenCalled();
  });

  it('does NOT call findByEmail when email is unchanged', async () => {
    const findByEmail = jest.fn();
    const repo = makeRepo({
      findById: jest.fn().mockResolvedValue(ALICE),
      findByEmail,
    });
    const handler = makePatchUserEmailHandler(repo);
    const req = makeReq('user-1', { email: ALICE.email });
    const res = makeRes();

    await handler(req, res);

    expect(findByEmail).not.toHaveBeenCalled();
  });
});

